use std::num::NonZeroUsize;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum SizeCalculationError {
    Overflow,
    EmptyInput,
}

pub fn calculate_total_file_size(file_sizes: &[u64]) -> Result<u64, SizeCalculationError> {
    if file_sizes.is_empty() {
        return Err(SizeCalculationError::EmptyInput);
    }

    file_sizes
        .iter()
        .try_fold(0u64, |acc, &size| {
            acc.checked_add(size)
                .ok_or(SizeCalculationError::Overflow)
        })
}

pub fn calculate_total_file_size_with_limit(
    file_sizes: &[u64],
    max_allowed: u64,
) -> Result<u64, SizeCalculationError> {
    if file_sizes.is_empty() {
        return Err(SizeCalculationError::EmptyInput);
    }

    let mut total = 0u64;
    
    for &size in file_sizes {
        total = total
            .checked_add(size)
            .ok_or(SizeCalculationError::Overflow)?;
        
        if total > max_allowed {
            return Err(SizeCalculationError::Overflow);
        }
    }

    Ok(total)
}

pub fn check_available_space(
    file_sizes: &[u64],
    available_space: u64,
) -> Result<bool, SizeCalculationError> {
    let total = calculate_total_file_size(file_sizes)?;
    Ok(total <= available_space)
}

pub struct BatchDownloadCalculator {
    max_batch_size: u64,
}

impl BatchDownloadCalculator {
    pub fn new(max_batch_size: u64) -> Self {
        Self { max_batch_size }
    }

    pub fn validate_batch(&self, file_sizes: &[u64]) -> Result<u64, SizeCalculationError> {
        calculate_total_file_size_with_limit(file_sizes, self.max_batch_size)
    }

    pub fn split_into_batches(&self, file_sizes: &[u64]) -> Result<Vec<Vec<u64>>, SizeCalculationError> {
        if file_sizes.is_empty() {
            return Err(SizeCalculationError::EmptyInput);
        }

        let mut batches = Vec::new();
        let mut current_batch = Vec::new();
        let mut current_size = 0u64;

        for &size in file_sizes {
            if size > self.max_batch_size {
                return Err(SizeCalculationError::Overflow);
            }

            let new_size = current_size.checked_add(size)
                .ok_or(SizeCalculationError::Overflow)?;

            if new_size > self.max_batch_size {
                if !current_batch.is_empty() {
                    batches.push(current_batch);
                    current_batch = Vec::new();
                }
                current_size = size;
                current_batch.push(size);
            } else {
                current_size = new_size;
                current_batch.push(size);
            }
        }

        if !current_batch.is_empty() {
            batches.push(current_batch);
        }

        Ok(batches)
    }
}

pub fn calculate_with_overhead(
    file_sizes: &[u64],
    overhead_percent: u8,
) -> Result<u64, SizeCalculationError> {
    if overhead_percent > 100 {
        return Err(SizeCalculationError::Overflow);
    }

    let base_total = calculate_total_file_size(file_sizes)?;
    
    let overhead = base_total
        .checked_mul(overhead_percent as u64)
        .and_then(|v| v.checked_div(100))
        .ok_or(SizeCalculationError::Overflow)?;
    
    base_total
        .checked_add(overhead)
        .ok_or(SizeCalculationError::Overflow)
}